addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request))
})

async function handleRequest(request) {
  if (request.method !== 'POST') {
    return new Response('Method not allowed', { status: 405 })
  }

  const url = new URL(request.url)
  
  if (url.pathname === '/auth/login') {
    return handleLogin(request)
  } else if (url.pathname === '/auth/validate') {
    return handleValidate(request)
  } else if (url.pathname === '/auth/logout') {
    return handleLogout(request)
  }
  
  return new Response('Not found', { status: 404 })
}

async function handleLogin(request) {
  try {
    const body = await request.json()
    const { username, password } = body

    if (!username || !password) {
      return jsonResponse({ error: 'Username and password required' }, 400)
    }

    const userKey = `user:${username}`
    const userData = await USERS_DB.get(userKey, 'json')

    if (!userData) {
      return jsonResponse({ error: 'Invalid credentials' }, 401)
    }

    const passwordHash = await hashPassword(password, userData.salt)
    
    if (passwordHash !== userData.passwordHash) {
      return jsonResponse({ error: 'Invalid credentials' }, 401)
    }

    const sessionToken = generateToken()
    const sessionData = {
      username: username,
      userId: userData.userId,
      createdAt: Date.now(),
      expiresAt: Date.now() + (24 * 60 * 60 * 1000)
    }

    await SESSIONS.put(`session:${sessionToken}`, JSON.stringify(sessionData), {
      expirationTtl: 86400
    })

    return jsonResponse({
      success: true,
      token: sessionToken,
      expiresAt: sessionData.expiresAt
    })

  } catch (error) {
    return jsonResponse({ error: 'Internal server error' }, 500)
  }
}

async function handleValidate(request) {
  try {
    const authHeader = request.headers.get('Authorization')
    
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return jsonResponse({ error: 'Missing or invalid authorization header' }, 401)
    }

    const token = authHeader.substring(7)
    const sessionData = await SESSIONS.get(`session:${token}`, 'json')

    if (!sessionData) {
      return jsonResponse({ error: 'Invalid or expired session' }, 401)
    }

    if (sessionData.expiresAt < Date.now()) {
      await SESSIONS.delete(`session:${token}`)
      return jsonResponse({ error: 'Session expired' }, 401)
    }

    return jsonResponse({
      valid: true,
      username: sessionData.username,
      userId: sessionData.userId
    })

  } catch (error) {
    return jsonResponse({ error: 'Internal server error' }, 500)
  }
}

async function handleLogout(request) {
  try {
    const authHeader = request.headers.get('Authorization')
    
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return jsonResponse({ error: 'Missing or invalid authorization header' }, 401)
    }

    const token = authHeader.substring(7)
    await SESSIONS.delete(`session:${token}`)

    return jsonResponse({ success: true, message: 'Logged out successfully' })

  } catch (error) {
    return jsonResponse({ error: 'Internal server error' }, 500)
  }
}

function generateToken() {
  const array = new Uint8Array(32)
  crypto.getRandomValues(array)
  return Array.from(array, byte => byte.toString(16).padStart(2, '0')).join('')
}

async function hashPassword(password, salt) {
  const encoder = new TextEncoder()
  const data = encoder.encode(password + salt)
  const hashBuffer = await crypto.subtle.digest('SHA-256', data)
  const hashArray = Array.from(new Uint8Array(hashBuffer))
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('')
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status: status,
    headers: {
      'Content-Type': 'application/json',
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'POST, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization'
    }
  })
}